learnerDiff.patch:
diff --git a/src/task-manager.ts b/src/task-manager.ts
index a08d57a..learner 100644
--- a/src/task-manager.ts
+++ b/src/task-manager.ts
@@ -18,5 +18,11 @@ export class TaskManager {
-    await this.saveTask(nextTask);
+    const previous = this.getTask(id);
+    if (!previous) throw new Error("Task not found");
+    const nextTask = { ...previous, done: !previous.done };
+    this.tasks = this.tasks.map((item) => item.id === id ? nextTask : item);
+    try { await this.saveTask(nextTask); }
+    catch { this.tasks = this.tasks.map((item) => item.id === id ? previous : item); }

referenceDiff.patch:
diff --git a/src/task-manager.ts b/src/task-manager.ts
index a08d57a..219ce2e 100644
--- a/src/task-manager.ts
+++ b/src/task-manager.ts
@@ -18,10 +18,16 @@ export class TaskManager {
-    const task = this.getTask(id);
-    if (!task) throw new Error("Task not found");
-    const nextTask = { ...task, done: !task.done };
-    await this.saveTask(nextTask);
+    const previous = this.getTask(id);
+    if (!previous) throw new Error("Task not found");
+    const nextTask = { ...previous, done: !previous.done };
+    this.error = "";
+    this.tasks = this.tasks.map((item) => item.id === id ? nextTask : item);
+    try {
+      await this.saveTask(nextTask);
+    } catch {
+      this.tasks = this.tasks.map((item) => item.id === id ? previous : item);
+      this.error = "Could not save task. Try again.";
+    }
